() => {
  // Find and hide any visible overlays
  const allOverlays = document.querySelectorAll('[id*="overlay"], [id*="gate"], [class*="overlay"], [class*="gate"]');
  const hidden = [];
  allOverlays.forEach(el => {
    const style = window.getComputedStyle(el);
    if (style.display !== 'none' && style.visibility !== 'hidden') {
      hidden.push({ id: el.id, class: el.className, display: style.display });
    }
    el.style.display = 'none';
  });
  return hidden;
}

