() => {
  // Directly dispatch click on the time cell of first row 
  const firstRow = document.querySelector('#news-body tr[data-id]');
  if (!firstRow) return { error: 'No rows found' };

  const timeCell = firstRow.querySelector('td:first-child');
  if (!timeCell) return { error: 'No time cell found' };

  // Click the time cell (not the link)
  timeCell.click();

  // Check if modal opened
  const overlay = document.getElementById('detail-modal-overlay');
  const isOpen = overlay && overlay.classList.contains('open');
  const modalBody = overlay ? overlay.querySelector('.detail-modal-body') : null;
  const modalContent = modalBody ? modalBody.innerHTML.substring(0, 500) : 'no body';

  return { 
    clicked: true, 
    rowId: firstRow.dataset.id,
    modalOpen: isOpen,
    modalContent: modalContent
  };
}

