  // Intercept the tier API to return Max tier
  await page.route('**/api/auth/tier', async (route) => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({
        tier: 'max',
        features: {
          terminal_access: true,
          sentiment_analysis: true,
          dedup_detection: true,
          date_filtering: true,
          api_access: true,
          csv_export: true,
          watchlist: true,
          ai_ticker_recommendations: true,
          price_analysis: true,
          advanced_analytics: true,
          custom_alerts: true
        },
        limits: { max_items: 500, rate_limit: '1000/minute', history_days: 1825 }
      })
    });
  });

  // Intercept auth/me to return a fake Max user
  await page.route('**/api/auth/me', async (route) => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({
        uid: 'test-max-user',
        email: 'test@example.com',
        display_name: 'Test Max User',
        tier: 'max'
      })
    });
  });

  // Navigate to terminal
  await page.goto('http://localhost:5173/terminal');
  await page.waitForTimeout(2000);

  // Hide auth gates that may still appear due to Firebase client-side checks
  await page.evaluate(() => {
    const gates = document.querySelectorAll('[id*="gate"], [id*="signin"], [class*="auth-gate"]');
    gates.forEach(el => el.style.display = 'none');
  });

  return 'Route interception set up, page reloaded';
}

