input.function:
() => {
  // Close the modal first
  const overlay = document.getElementById('detail-modal-overlay');
  overlay.classList.remove('open');

  // Check row hover cursor
  const rows = document.querySelectorAll('#news-body tr[data-id]');
  const firstRow = rows[0];
  const rowCursor = firstRow ? window.getComputedStyle(firstRow).cursor : null;

  // Check modal background color (dark theme)
  const modal = overlay.querySelector('.modal');
  const modalBg = modal ? window.getComputedStyle(modal).backgroundColor : null;
  const overlayBg = window.getComputedStyle(overlay).backgroundColor;

  // Check that headline links have href attributes
  const link = firstRow ? firstRow.querySelector('a') : null;
  const linkHref = link ? link.href : null;
  const linkTarget = link ? link.target : null;

  return {
    rowCursor,
    modalBg,
    overlayBg,
    linkHref: linkHref ? linkHref.substring(0, 80) : null,
    linkTarget
  };
}

