input.function:
() => {
  // Verify that clicking a link does NOT open the modal
  const rows = document.querySelectorAll('#news-body tr[data-id]');
  const firstRow = rows[0];
  const link = firstRow.querySelector('a');

  // Simulate a click on the link element - the click handler should return early
  // due to `if (e.target.closest("a")) return;`
  const event = new MouseEvent('click', { bubbles: true, cancelable: true });
  // Prevent actual navigation
  link.addEventListener('click', (e) => e.preventDefault(), { once: true });
  link.dispatchEvent(event);

  const overlay = document.getElementById('detail-modal-overlay');
  const modalOpened = overlay.classList.contains('open');

  return { 
    linkClicked: true,
    modalOpened,
    linkText: link.textContent.substring(0, 60)
  };
}

